#include <stdio.h>
#define MOD 1000000007
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, m;
        scanf("%d %d", &n, &m);
        int arr[n];
        for (int i = 0; i < n; i++) arr[i] = 0;
        int commands[m][3];
        for (int i = 0; i < m; i++) {
            scanf("%d %d %d", &commands[i][0], &commands[i][1], &commands[i][2]);
        }
        for (int i = 0; i < m; i++) {
            if (commands[i][0] == 1) {
                for (int j = commands[i][1] - 1; j < commands[i][2]; j++) {
                    arr[j] = (arr[j] + 1) % MOD;
                }
            } else {
                for (int j = commands[i][1] - 1; j < commands[i][2]; j++) {
                    if (commands[j][0] == 1) {
                        for (int k = commands[j][1] - 1; k < commands[j][2]; k++) {
                            arr[k] = (arr[k] + 1) % MOD;
                        }
                    }
                }
            }
        }
        for (int i = 0; i < n; i++) printf("%d ", arr[i]);
        printf("\n");
    }
    return 0;
}

