import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int m = sc.nextInt();
            int[] arr = new int[n];
            int[][] commands = new int[m][3];
            for (int i = 0; i < m; i++) {
                commands[i][0] = sc.nextInt();
                commands[i][1] = sc.nextInt();
                commands[i][2] = sc.nextInt();
            }
            for (int i = 0; i < m; i++) {
                if (commands[i][0] == 1) {
                    for (int j = commands[i][1] - 1; j < commands[i][2]; j++) {
                        arr[j] = (arr[j] + 1) % 1000000007;
                    }
                } else {
                    for (int j = commands[i][1] - 1; j < commands[i][2]; j++) {
                        if (commands[j][0] == 1) {
                            for (int k = commands[j][1] - 1; k < commands[j][2]; k++) {
                                arr[k] = (arr[k] + 1) % 1000000007;
                            }
                        }
                    }
                }
            }
            for (int i = 0; i < n; i++) System.out.print(arr[i] + " ");
            System.out.println();
        }
